INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('locality-814ced5a-moex-00306', 'locality-814ced5a', 'locality-814ced5a-moex-110-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「在人們的感覺上，光陰如順流而下的波浪，品學卻如逆流而上的船舶，前者稍縱即逝，後者步步費 力，相形之下，頗欠公平……。然而光陰的消逝，有一定的數量和速度，固然沒有辦法減少，可是也 不會增加。吾人追求知識，鍛鍊技能，涵養德性，開拓胸襟，卻可以憑主觀的意願，提高進度。種瓜 得瓜，種豆得豆，而種瓜種豆，操之在我。」 下列選項，何者最接近上文意旨？', '["人生而不平等，只能調整心態，樂觀面對", "在不公平的環境之下，品學提升相當困難", "人只有自我體悟，才能明白公平是主觀的", "時間是公平的，全人的提升依靠自我努力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:30+00:00", "source_pdf_sha1": "446a8cd8f77b", "answer_pdf_sha1": "ad20df8aa8a5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00307', 'locality-814ced5a', 'locality-814ced5a-moex-110-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「『雅舍』非我所有，我僅是房客之一。但思『天地者萬物之逆旅』，人生本來如寄，我住『雅舍』一 日，『雅舍』即一日為我所有。即使此一日亦不能算是我有，至少此一日『雅舍』所能給予之苦辣酸 甜，我實躬受親嚐。」 根據上文，下列選項何者最符合文意？', '["覓得雅舍，渴望長居此處", "暫居雅舍，體會生活點滴", "久居雅舍，企盼遷往他方", "將別雅舍，內心眷戀不捨"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:30+00:00", "source_pdf_sha1": "446a8cd8f77b", "answer_pdf_sha1": "ad20df8aa8a5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00308', 'locality-814ced5a', 'locality-814ced5a-moex-110-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「時光總要過去，想到愈活愈冷漠的情感，人們慢慢成長，純真也慢慢蒼老，這是真的！我忽然覺得 自己應該轉向，去擁抱渾沌質樸，可是每次我說花會凋落真是一個問題的時候，總會遭人白眼——也 許現實人生不能太有情感，所以我總是一個人去看山看水，聽風聽雨。」 根據上文，作者為何說「花會凋落」真是一個問題？', '["生物的自然現象值得觀察", "性情中人對於物象的感懷", "凡是美景只能夠獨自欣賞", "人心逐漸蒼老如花的凋謝"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:30+00:00", "source_pdf_sha1": "446a8cd8f77b", "answer_pdf_sha1": "ad20df8aa8a5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00309', 'locality-814ced5a', 'locality-814ced5a-moex-110-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「如今回想，我在文章中不時笑談她的斯巴達式嚴格管教，表面看似輕鬆，實則內心含恨。母親讀我 文章，既不辯白、也不討饒，只在介意處以長線標示，卻隱忍地將不滿深深埋藏。我是不是對母親太 過嚴厲了？年長後的我是故意用文字報復著她嗎？我猶然懷恨缺乏耐性的她在我年幼時對我無端的 鞭笞嗎？歷史是這樣殘酷的重演著嗎？童年時，母親用密密的鞭影宰制毫無自衛能力的我；母親年老 了，我用她老人家全無招架餘地的文字回報她！我不是比她更殘忍嗎？」 根據上文，下列敘述何者正確？', '["母親故意以隱忍的方式對作者進行精神的鞭笞", "本段文字運用對比書寫的手法，流露懊悔與自省之情", "母親以長線標示之處，代表著深切反省，值得仔細玩味", "本文印證了棒下出孝子的說法，充盈著母慈女愛的幸福氛圍"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:30+00:00", "source_pdf_sha1": "446a8cd8f77b", "answer_pdf_sha1": "ad20df8aa8a5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00310', 'locality-814ced5a', 'locality-814ced5a-moex-110-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「紀伯倫在其作品裡講了一隻狐狸覓食的故事：狐狸欣賞著自己在晨曦中的身影說：『今天我要用一隻 駱駝當作午餐呢！』整個上午，牠奔波著，尋找駱駝。但當正午的太陽照在牠的頭頂時，牠再次看了 一眼自己的身影，於是說：『一隻老鼠也就夠了。』狐狸之所以犯了兩次截然不同的錯誤，與牠選擇 晨曦和正午的陽光作為鏡子有關。晨曦不負責任的拉長了牠的身影，使牠錯誤的認為自己就是萬獸之 王，並且力大無窮，無所不能，而正午的陽光又讓牠對著自己已縮小的身影妄自菲薄。」 根據上文之寓意，下列選項何者最符合意旨？', '["酸葡萄心態是成功的絆腳石", "自信是一切能力的基石，能克服萬難", "認清真實的自己，才不至於錯估能力", "盲目追求成功，猶如鏡花水月、空中樓閣"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:30+00:00", "source_pdf_sha1": "446a8cd8f77b", "answer_pdf_sha1": "ad20df8aa8a5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00311', 'locality-814ced5a', 'locality-814ced5a-moex-110-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「每一個人或多或少都有些缺陷，有些暴露在外，有些隱藏在內。可是，這些缺陷都不妨礙一個人的 真正成就，反而會激勵他走上成功之路。所以說，缺陷固然不幸，但並不等於絕望；倘若屈服在自己 的缺陷之下，那才是耽誤了自己呢！」 若要用一句話勉勵有缺陷的人，下列選項，最貼近本文意旨的是：', '["接受天命，不平凡的人該有不平凡的作為", "勇敢面對問題，才能找出解決問題的策略", "天生我材必有用，缺陷是老天送的最佳禮物", "在各種快樂當中，辛勞而得的果實最為甜美"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:30+00:00", "source_pdf_sha1": "446a8cd8f77b", "answer_pdf_sha1": "ad20df8aa8a5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00312', 'locality-814ced5a', 'locality-814ced5a-moex-110-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「達文西很喜歡運用相反事物之間的張力，透過不確定和模糊的效果來創造情節。達文西的《蒙娜麗 莎的微笑》，畫中她神祕的似笑非笑被解讀成正義與邪惡、同情與殘忍，以及誘惑與天真之間的對立。 她的眼角和嘴角含糊不清，提供很大的詮釋空間，整幅畫給人很多想像。」 關於本文傳達的意旨，下列選項何者錯誤？', '["藝術家的作品力道往往在於明確清晰的情節創造", "藝術評論家的詮釋差異來自於對作品的不同解讀", "畫作的不確定與模糊效果，提供觀看者的詮釋空間", "畫家運用相反事物的張力，提供觀看者的想像空間"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:30+00:00", "source_pdf_sha1": "446a8cd8f77b", "answer_pdf_sha1": "ad20df8aa8a5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00313', 'locality-814ced5a', 'locality-814ced5a-moex-110-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「我常將理想或認為對的事情，在兩個小時的會議裡反覆論述，但夥伴們在前半個小時就厭煩了。王 老師推動的這套教學法，正好可以轉化為主管如何開好會議的參考指引，因為整個會議需要經過設計， 讓事情獲得有效的討論和決策，並提升夥伴們的能力。」 根據上文，「這套教學法」的主要特點為何？', '["老師透過討論提升課程設計能力", "老師依據學生能力決定學習內容", "學生們藉討論思辨形成有效學習", "學生們在創意活動中體驗新鮮感"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:30+00:00", "source_pdf_sha1": "446a8cd8f77b", "answer_pdf_sha1": "ad20df8aa8a5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00314', 'locality-814ced5a', 'locality-814ced5a-moex-110-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「前些時，在南部鄉下，走訪一家醃漬工廠……在老闆熱情引薦下，打開一罐封藏多時的老甕，嗅聞 這一小小空間。幽暗的甕中，瓜身半浮，散發濃郁氣味。那豈只是美好芳香，似乎還有深奧的生活提 示。霎時，我亦隱隱感覺，旅行一如醃漬的甕裡乾坤。隨著時日的緩慢流轉，食材在甕裡逐漸脫水、 發酵，歷經微生物的轉化，最終醞釀出獨特的風味。看著老甕漆黑無限的裡面，我無從敘述那難以洞 澈的美好。好像只那一個『裡』，即足以說明一切。」 上文說明作者走訪臺灣各地的態度與體悟，最適當的是：', '["用心觀察社區居民的日常生活面貌，可以真正聽到民眾的心聲，活化社區再造", "不追求討喜、華麗的旅程，而是以內斂、沉澱的態度，安於在地體驗，就能發現新風景", "臺灣的社會到處充滿人情味，如果能夠誠心以對，好客的老闆，總不吝嗇分享家藏美味", "許多藏在社區裡的古老文化，就像醃漬的功夫，是先民的智慧，經驗的累積，應該好好保護"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:30+00:00", "source_pdf_sha1": "446a8cd8f77b", "answer_pdf_sha1": "ad20df8aa8a5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00315', 'locality-814ced5a', 'locality-814ced5a-moex-110-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「落羽松的葉子，落入水中，經由微生物的分解，葉子的磷含量，又重回水中，落羽松的根將磷又迅 速吸收回去。吸收的快，釋放的慢，這能保持自然水中只有極低濃度的磷，卻有大量的磷固定在植物 體中。磷是所有生物生長所需要的營養份，水中的磷含量過高，會造成藻類滋生。藻類白天旺盛的光 合作用與夜間的呼吸作用，將導致水中溶氧量日夜之間變化太大，使許多魚類無法生存，稱為『水質 優養化』。落羽松的功能，顯示自然界有一個非常奇妙的法則，使水生植物大量生長，水又可以保持 乾淨。研究者提出：『人類對濕地植物的了解太少，許多主觀，常有偏差。人類對不確定功能的植物， 需要保留。』」 下列選項，何者最接近本文旨意？', '["自然界中磷無法自給自足，人類應適度操控", "以落羽松為例，說明人類應該保留各種植物", "大量種植落羽松無助於解決水質優養化的困擾", "落羽松藉由吸收與製造磷，成為魚類主要食物"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:30+00:00", "source_pdf_sha1": "446a8cd8f77b", "answer_pdf_sha1": "ad20df8aa8a5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL)
